class SecurityHandler implements SOAPHandler<SOAPMessageContext> {

    private static final String WSU_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd";
    private static final String WSSE_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-secext-1.0.xsd";
    private static final Set<String> processedMessageIds = Collections.newSetFromMap(new ConcurrentHashMap<>());
    private static final long CLEANUP_INTERVAL = 600000; // 10 minutes
    private static long lastCleanup = System.currentTimeMillis();

    @Override
    public boolean handleMessage(SOAPMessageContext context) {
        Boolean isOutbound = (Boolean) context.get(MessageContext.MESSAGE_OUTBOUND_PROPERTY);

        if (!isOutbound) {
            try {
                SOAPMessage message = context.getMessage();
                SOAPHeader header = message.getSOAPHeader();

                if (header == null) {
                    throw new SOAPException("Missing SOAP Header");
                }

                TimestampInfo timestampInfo = extractTimestamp(header);
                
                if (timestampInfo == null) {
                    throw new SOAPException("Missing WS-Security Timestamp");
                }

                validateTimestamp(timestampInfo);
                checkReplay(timestampInfo.messageId);
                
                cleanupOldMessages();

            } catch (Exception e) {
                throw new RuntimeException("Security validation failed: " + e.getMessage(), e);
            }
        }

        return true;
    }

    private TimestampInfo extractTimestamp(SOAPHeader header) throws Exception {
        Iterator<?> securityHeaders = header.getChildElements(
            new QName(WSSE_NS, "Security", "wsse"));

        if (!securityHeaders.hasNext()) {
            return null;
        }

        SOAPElement security = (SOAPElement) securityHeaders.next();
        
        Iterator<?> timestamps = security.getChildElements(
            new QName(WSU_NS, "Timestamp", "wsu"));

        if (!timestamps.hasNext()) {
            return null;
        }

        SOAPElement timestamp = (SOAPElement) timestamps.next();
        String messageId = timestamp.getAttributeValue(new QName(WSU_NS, "Id", "wsu"));
        
        String created = null;
        String expires = null;

        Iterator<?> children = timestamp.getChildElements();
        while (children.hasNext()) {
            Object child = children.next();
            if (child instanceof SOAPElement) {
                SOAPElement element = (SOAPElement) child;
                String localName = element.getLocalName();
                
                if ("Created".equals(localName)) {
                    created = element.getTextContent();
                } else if ("Expires".equals(localName)) {
                    expires = element.getTextContent();
                }
            }
        }

        if (created == null) {
            throw new SOAPException("Missing Created timestamp");
        }

        TimestampInfo info = new TimestampInfo();
        info.messageId = messageId != null ? messageId : UUID.randomUUID().toString();
        info.created = parseTimestamp(created);
        info.expires = expires != null ? parseTimestamp(expires) : null;

        return info;
    }

    private Date parseTimestamp(String timestamp) throws Exception {
        SimpleDateFormat[] formats = {
            new SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss'Z'"),
            new SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'"),
            new SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ssX")
        };

        for (SimpleDateFormat format : formats) {
            format.setTimeZone(TimeZone.getTimeZone("UTC"));
            try {
                return format.parse(timestamp);
            } catch (Exception e) {
                // Try next format
            }
        }
        
        throw new Exception("Invalid timestamp format: " + timestamp);
    }

    private void validateTimestamp(TimestampInfo info) throws Exception {
        long now = System.currentTimeMillis();
        long created = info.created.getTime();
        
        if (created > now + 60000) {
            throw new Exception("Timestamp is in the future");
        }

        if (now - created > 300000) {
            throw new Exception("Timestamp is too old");
        }

        if (info.expires != null) {
            long expires = info.expires.getTime();
            if (now > expires) {
                throw new Exception("Message has expired");
            }
        }
    }

    private void checkReplay(String messageId) throws Exception {
        if (processedMessageIds.contains(messageId)) {
            throw new Exception("Replay attack detected - message ID already processed");
        }
        processedMessageIds.add(messageId);
    }

    private void cleanupOldMessages() {
        long now = System.currentTimeMillis();
        if (now - lastCleanup > CLEANUP_INTERVAL) {
            processedMessageIds.clear();
            lastCleanup = now;
        }
    }

    @Override
    public boolean handleFault(SOAPMessageContext context) {
        return true;
    }

    @Override
    public void close(MessageContext context) {
    }

    @Override
    public Set<QName> getHeaders() {
        Set<QName> headers = new HashSet<>();
        headers.add(new QName(WSSE_NS, "Security"));
        return headers;
    }

    private static class TimestampInfo {
        String messageId;
        Date created;
        Date expires;
    }
}

