        SOAPMessage soapMessage = messageFactory.createMessage();

        SOAPPart soapPart = soapMessage.getSOAPPart();
        SOAPEnvelope envelope = soapPart.getEnvelope();

        SOAPHeader header = envelope.getHeader();
        if (header == null) {
            header = envelope.addHeader();
        }

        addSecurityHeader(header);

        SOAPBody body = envelope.getBody();
        QName bodyName = new QName("http://localhost:8080/payment", "processPayment");
        SOAPBodyElement bodyElement = body.addBodyElement(bodyName);

        SOAPElement cardNumber = bodyElement.addChildElement("cardNumber");
        cardNumber.setTextContent("4111111111111111");

        SOAPElement amount = bodyElement.addChildElement("amount");
        amount.setTextContent("100.50");

        SOAPElement currency = bodyElement.addChildElement("currency");
        currency.setTextContent("USD");

        SOAPElement merchantId = bodyElement.addChildElement("merchantId");
        merchantId.setTextContent("MERCHANT123");

        soapMessage.saveChanges();

        System.out.println("Request SOAP Message:");
        soapMessage.writeTo(System.out);
        System.out.println();

        SOAPMessage response = connection.call(soapMessage, wsdlURL);

        System.out.println("\nResponse SOAP Message:");
